import type {
  AgentifiedConfig,
  DiscoverResponse,
  DiscoverTool,
  DiscoverToolInput,
  PrefetchOptions,
  RankedTool,
  ToolDefinition,
  RegisterResponse,
  ServerTool,
  ServerToolFields,
} from "./types.js";

export class Agentified {
  private serverUrl: string;

  constructor(config: AgentifiedConfig) {
    this.serverUrl = config.serverUrl.replace(/\/+$/, "");
  }

  async register(tools: ToolDefinition[]): Promise<RegisterResponse> {
    const serverTools = tools.map(toServerTool);
    const res = await fetch(`${this.serverUrl}/api/v1/tools`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ tools: serverTools }),
    });
    if (!res.ok) {
      const body = (await res.json()) as { error?: string };
      throw new Error(body.error ?? `register failed (${res.status})`);
    }
    return res.json() as Promise<RegisterResponse>;
  }

  async prefetch(options: PrefetchOptions): Promise<DiscoverResponse> {
    const lastUserMsg = [...options.messages]
      .reverse()
      .find((m) => m.role === "user");
    if (!lastUserMsg) return { tools: [] };

    return this.discover(lastUserMsg.content, options.topK ?? 10);
  }

  asDiscoverTool(options?: { topK?: number }): DiscoverTool {
    const limit = options?.topK ?? 10;
    return {
      name: "discover_tools",
      description:
        "Discover relevant tools by semantic search. Provide a query string or multiple queries.",
      inputSchema: {
        type: "object",
        properties: {
          query: {
            type: "string",
            description: "A single search query to find relevant tools",
          },
          queries: {
            type: "array",
            items: { type: "string" },
            description:
              "Multiple search queries to find relevant tools (results merged and deduplicated)",
          },
        },
      },
      execute: async (input: DiscoverToolInput): Promise<RankedTool[]> => {
        if (input.queries) {
          const results = await Promise.all(
            input.queries.map((q) => this.discover(q, limit))
          );
          return dedupeByName(results.flatMap((r) => r.tools));
        }
        const { tools } = await this.discover(input.query ?? "", limit);
        return tools;
      },
    };
  }

  private async discover(
    query: string,
    limit: number
  ): Promise<DiscoverResponse> {
    const res = await fetch(`${this.serverUrl}/api/v1/discover`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ query, limit }),
    });
    if (!res.ok) {
      const body = (await res.json()) as { error?: string };
      throw new Error(body.error ?? `discover failed (${res.status})`);
    }
    return res.json() as Promise<DiscoverResponse>;
  }
}

function dedupeByName(tools: RankedTool[]): RankedTool[] {
  const map = new Map<string, RankedTool>();
  for (const t of tools) {
    const existing = map.get(t.name);
    if (!existing || t.score > existing.score) map.set(t.name, t);
  }
  return [...map.values()];
}

function toServerTool(def: ToolDefinition): ServerTool {
  const fields: ServerToolFields = {
    name: def.name,
    description: def.description,
  };
  if (def.inputSchema) fields.input_schema = JSON.stringify(def.inputSchema);
  if (def.outputSchema) fields.output_schema = JSON.stringify(def.outputSchema);

  const tool: ServerTool = {
    name: def.name,
    description: def.description,
    parameters: def.inputSchema ?? {},
    fields,
  };
  if (def.metadata) tool.metadata = def.metadata;
  return tool;
}
